class Trie {
public:
    Trie() {}

    void insert(string word) {
        Node* curr = root;
        for (char c : word) {
            if (!curr->children[c - 'a']) {
                curr->children[c - 'a'] = new Node();
            }
            curr = curr->children[c - 'a'];
        }
        curr->is_end_of_word = true;
    }

    bool search(string word) {
        Node* curr = root;
        for (char c : word) {
            if (!curr->children[c - 'a']) {
                return false;
            }
            curr = curr->children[c - 'a'];
        }
        return curr->is_end_of_word;
    }

    bool startsWith(string prefix) {
        Node* curr = root;
        for (char c : prefix) {
            if (!curr->children[c - 'a']) {
                return false;
            }
            curr = curr->children[c - 'a'];
        }
        return curr->is_end_of_word;
    }
};

class Node {
public:
    bool is_end_of_word;
    Node* parent;
    Node* children[26];
};
